def findShortestCommonSupersequence(str1, str2):
    n, m = len(str1), len(str2)

    # Step 1: Build LCS Table
    dp = [[0] * (m + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if str1[i - 1] == str2[j - 1]:
                dp[i][j] = 1 + dp[i - 1][j - 1]
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # Step 2: Backtrack
    res = []
    i, j = n, m

    while i > 0 and j > 0:
        if str1[i - 1] == str2[j - 1]:
            res.append(str1[i - 1])
            i -= 1
            j -= 1
        elif dp[i - 1][j] > dp[i][j - 1]:
            res.append(str1[i - 1])
            i -= 1
        else:
            res.append(str2[j - 1])
            j -= 1

    # Add leftovers
    while i > 0:
        res.append(str1[i - 1])
        i -= 1
    while j > 0:
        res.append(str2[j - 1])
        j -= 1

    return "".join(res[::-1])

