            }
        }
    }

    // Step 2: Backtrack logic
    let res = [];
    let i = n, j = m;

    while (i > 0 && j > 0) {
        if (str1[i - 1] === str2[j - 1]) {
            res.push(str1[i - 1]);
            i--; j--;
        } else if (dp[i - 1][j] > dp[i][j - 1]) {
            res.push(str1[i - 1]);
            i--;
